const Q_CHEMISTRY_2018_MODEL_II=[{"id": "objective>Chemistry>2018-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances can be used to identify water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span> or Copper(II) sulfate is a common substance used to test for the presence of water. When it is anhydrous (without water), it is white. When water is added, it turns blue. This is a common test for water in a chemistry lab.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2018-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is γ in the equation: Y = -Log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>[H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Δ</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> PH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">POH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PK</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the equation Y = -Log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>[H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>], γ represents the pH. The pH is a measure of the hydrogen ion concentration of a solution. Solutions with a high concentration of hydrogen ions have a low pH and solutions with a low concentrations of hydrogen ions have a high pH.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2018-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the percentage composition of carbon <br/> in Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ? <br/> [ Ca = 40.0, 0= 16.0, C = 12.0, H= 1.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.2%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.8%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.4%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.7%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">. % of C in Ca(HCO3)2  <br/> Molar mass of Ca(HCO3)2 = 40+(1+12+(16*3))2 <br/> =40+(13+48)2 <br/> =40+122 <br/> =162 <br/> C/Ca(HCO3)2 x 100 <br/> =12 * 2/162 * 100 <br/> =14.8%</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2018-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The measure of the average kinetic energy of the molecules of a gas is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average kinetic energy of the molecules of a gas is directly proportional to the temperature of the gas. This is a fundamental principle of kinetic molecular theory. Therefore, the measure of the average kinetic energy of the molecules of a gas is the temperature.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2018-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soap lather is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gas dispersed in a liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid dispersed in a gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid dispersed in a liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid dispersed in a liquid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soap lather is a collidal system in which air (gas) is the dispersed phase and soap solution (liqud) is the dispersion medium.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>2018-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under high pressure, real gases deviate from ideality due to the fact that their molecules </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">experience repulsive forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have become more energetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have become less energetic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">collide inelastically</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ideal gas is any gas that obeys boyle's law or charles' law under high pressure real gases deviate from ideality because the molecules of the gas becomes more restricted and their intermolecular forces of attraction appreciated , hence they become less energetic.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2018-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a form of biotechnology?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fermentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jewelry manufacture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Battery manufacture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic extraction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fermentation is the oldest form of biotechnology whereby microrganism (the bio aspect) are used to convert sugar to alkanol and flour to bread (the technology aspect).</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2018-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bonding pair of electrons in a hydrogen chloride molecule is pulled towards the chlorine atom because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine has a larger atomic size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine has a larger atomic mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine is more electronegative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no bonding orbitals within the hydrogen atom</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bonding pair of electrons in a hydrogen chloride molecule is pulled towards the chlorine atom because chlorine is more electronegative. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The more electronegative atom attracts the bonding pair of electrons more towards itself.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>2018-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">J + K  → L + M <br/> In the reaction above, the forward reaction above, the forward reaction is favoured if the concentration of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K is reduced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J is reduced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">L is increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J is increased </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All other changes will shift the equilibrium position backward but an increase in the concentration of J will shift the equilibrium forward to annul the effect of the change and re-establish another equilibrium.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2018-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The results obtained in a kinetic study of the reaction  <br/> A + B → E + F at 25°C are given in the table below. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Experiment</td><td style=\"border:1px solid black;text-align:center;\"> Conc. of A (moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) </td><td style=\"border:1px solid black;text-align:center;\">Conc of B (moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)</td><td style=\"border:1px solid black;text-align:center;\"> Rate (moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">I <br/> II <br/> III</td><td style=\"border:1px solid black;text-align:center;\">0.20 <br/> 0.20 <br/> 0.40</td><td style=\"border:1px solid black;text-align:center;\">0.20 <br/> 0.40 <br/> 0.20</td><td style=\"border:1px solid black;text-align:center;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td></tr></table></div> <br/> What is the rate law for this reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let the rate law be  <br/> Rate = k[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span> <br/> From experiment I and II <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">II</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">k(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>(0.40)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><hr size=\"1\" />k(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.0×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span><hr size=\"1\" />2.0×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td></tr></table></div> <br/> 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span> = 4 = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span> = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> y = 2 <br/> From experiments I and III <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">III</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">k(0.40)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><hr size=\"1\" />k(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>(0.20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4.0×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span><hr size=\"1\" />2.0×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td></tr></table></div> <br/> 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span> = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> <br/> x = 1 <br/> Substitute for x and y in the rate law; <br/> Rate = k[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "RATE OF CHEMICAL REACTION : CONCENTRATION OR TIME CURVES"}, {"id": "objective>Chemistry>2018-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Petrochemistry is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pure chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">applied chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biochemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental chemistry</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Applied chemistry refers to the practical application of chemical principles and techniques to solve real-world problems and create useful products. Petrochemistry is a branch of applied chemistry that deals specifically with the chemical processes and transformations involved in the extraction, refining, and processing of petroleum and its derivatives.</div>", "topic": "RATE OF CHEMICAL REACTION : CONCENTRATION OR TIME CURVES"}, {"id": "objective>Chemistry>2018-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A colourless gas with a pungent smell is evolved when dilute hydrochloric acid is added to a sample of a salt. The gas evolved could turn</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acidified K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> solution colourles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidified KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> solution colourless</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> solution green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> paper black</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the potassium manganate(VII) solution is acidified with dilute sulfuric acid, the purple solution becomes colourless.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2018-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> <br/> The energy change taking place in the reaction above is enthalpy of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Formation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy change taking place in the reaction above is enthalpy of neutralization. <br/> N.B: Neutralization reactions involves an acid and a base to give water and salt <br/> H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> represents an acid <br/> OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> represents a base.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2018-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An alkane with 49 carbon atoms contain 100 hydrogen atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition reactions occur between alkanes and chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Butane has a lower boiling point than propane.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pentane has five isomers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula for alkanes is CnH2n+2. For an alkane with 49 carbon atoms (n = 49), the number of hydrogen atoms can be calculated as follows: <br/>  <br/> Number of hydrogen atoms (H) = 2n + 2 <br/> Number of hydrogen atoms (H) = 2 * 49 + 2 <br/> Number of hydrogen atoms (H) = 98 + 2 <br/> Number of hydrogen atoms (H) = 100 <br/>  <br/> So, an alkane with 49 carbon atoms contains 100 hydrogen atoms.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2018-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about an equilibrium system is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Forward and backward reactions occur  <br/> at the same rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The concentrations of reactants must  <br/> equal that of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The concentrations of, reactants and products can be changed by adding a catalyst,</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The concentrations of reactants and  <br/> products are not affected by a change in temperature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium is a state of a system where there is no observable change in the properties of the system with respect to time</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2018-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the molar mass of X(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 162 g mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> , determine the relative atomic mass of X. <br/> [H = 1.0, C = 12.0, 0 = 16.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48</div>", "<div style=\"font-family:Cambria;font-size:17px;\">61</div>", "<div style=\"font-family:Cambria;font-size:17px;\">101</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molar mass of X(HCO3)2 is given as 162 g mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The molar mass of HCO3 is (1.0 + 12.0 + (3*16.0)) = 61.0 g mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Since there are two HCO3 in the compound, the total molar mass of HCO3 in the compound is 2*61.0 = 122.0 g mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Subtracting this from the total molar mass of the compound gives the relative atomic mass of X as 162.0 - 122.0 = 40 g mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2018-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanols can be manufactured from alkenes by the initial reaction of alkenes with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine in tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrated tetraoxosulphate(VI) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aqueous potassium tetraoxomanganate(VII).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide solution.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alkene reacts with conc. H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> to yield an alkyl hydrogen tetraoxosulphate (VI). The compound formed undergoes hydrolysis when boiled with water to yield an alcohol.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2018-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these metals reacts with steam reversibly only when red-hot? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron reacts with steam only when it is red-hot and the reaction is reversible. The reaction is 3Fe(s) + 4H2O(g) ⇌ Fe3O4(s) + 4H2(g). This is a redox reaction where iron is oxidized and water is reduced.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2018-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an alloy of mercury?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soft solder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amalgam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stainless steel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coinage bronze</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alloy of mercury is known as an amalgam. Amalgams are a combination of mercury with another metal. They are used in dentistry and for the extraction of gold and silver.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2018-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many electrons are in the ion F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> ? [F]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> ------ (1) <br/> The equation above shows that one mole of electron is added to the neutral atom of fluorine which has nine electrons to give fluoride ion with a total of 10 electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two elements G and H have electronegativity values 0.8 and 3.2 respectively. What is the type of bond present in the compound formed when the two element combine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coordinate covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bond between two elements with electronegativity values 0.8 and 3.2 is ionic. Ionic bonds form when there is a large difference in electronegativity between the two atoms. The difference in electronegativity between these two elements is 2.4, which is large enough to form an ionic bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following specied does not contain a co-ordinate bond?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CCL</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A coordinate bond, also known as a dative bond, is a kind of 2-center, 2-electron covalent bond in which the two electrons derive from the same atom. The molecule CCl does not contain a coordinate bond. The other molecules (Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) do contain coordinate bonds.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All the following can be gotten from the electronic configuration of a transition element except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They possess magnetic properties </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ability to form complex ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable oxidation states </div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point of the element</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration of a transition element can tell us about its magnetic properties, its ability to form complex ions, and its variable oxidation states. However, it does not provide information about the boiling point of the element. The boiling point of an element is determined by the strength of the bonds between its atoms, which is not directly related to its electronic configuration.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes occur during fractional distillation of petroleum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Condensation and diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion and evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion and sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Evaporation and condensation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fractional distillation is a series of processes of evaporation and condensation at a number of points in a vertical column.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2018-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite is used as a dry lubricant due to the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mobile electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">octahedral structures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">layered structures</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite is used as a dry lubricant due to its layered structure. The layers of carbon atoms in graphite are held together by weak Van der Waals forces, which allow the layers to slide over each other easily. This property makes graphite an excellent dry lubricant.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2018-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of Distilled water is added to 80cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.50 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> hydrochloric acid, the new concentration of the acid will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.10 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 0.50 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 80cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> x = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> c<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = Unknown <br/> Recall: From Dilution Theory <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + x) <br/> (0.50)(80) = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (80 + 20) <br/> 40 = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(100) <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.4 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2018-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 0.25moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> Hydrochloric acid would be required to dissolve 0.48g of magnesium completely? [My = 24.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">160cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">320cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of reaction <br/> 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Mg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">Mg</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.48<hr size=\"1\" />24</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02mol</td></tr></table></div> <br/> From the equation above; <br/> 1 mole of mg is dissolved in 2 mole of HCl <br/> 0.02mole of Mg will be dissolved in 0.02 × 2 mole of HCl <br/> Number of moles of HCl = 0.04 mole <br/> Since number of moles = concentration × volume <br/> 0.04mole = 0.25 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × vol <br/> Volume of HCl = 0.04/0.25 <br/> = 0.16dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Volume of HCl = 0.16 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 1000 = 160cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2018-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is also referred to as laughing gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Laughing gas is a common name for nitrous oxide, which is chemically represented as N2O. Therefore, the correct answer is N2O.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2018-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about rare gases are correct? <br/> I. Their outermost shells are fully filled  <br/> II. They are generally unreactive  <br/> III. They are stable <br/> IV. They have one pair of electrons in their outermost shell</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rare gases, also known as noble gases, are characterized by their full outermost electron shells and their general unreactivity. Statement IV is incorrect because rare gases do not have just one pair of electrons in their outermost shell, they have a full shell. Therefore, the correct answer is 'I, II and III only'.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2018-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of Sulphur to tetraoxosulphate (VI) acid by contact process is schematically represented as S → SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. The correct change of the oxidation state of sulphur at each stage of the above scheme is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+4, +1, +1, 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2, +4, +2, +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2, +4, 0, 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+4, +2, 0, 0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation numbers of sulphur in S, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> are 0, +4, +6, +6 and +6 respectively. change of oxidation number in each stage is final value minus initial value. <br/> Hence the changes are [+4, -0], [+6 - (+4)], [+6 - (+6)] and [+6 -(+6)] i.e +4, +2, 0 and 0 respectively.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2018-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Before a reaction could take place, there should be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionization of reactant particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breakage of bonds of products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breakage of bonds of reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization of product particles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Activation energy must be achieved before reaction begin. This is because in any chemical reaction, chemical bonds in the reactants are broken, and new bonds in the products are formed</div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2018-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What are the possible oxidation numbers of an element with atomic number 9?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-1 and +6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-7 and +1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-3 and +5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1 and +7</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An element with atomic number 9 has a shell notation 2,7 therefore it is either it loses 7 electron or gain one electron to becone isoelectronic with a noble gas.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen are sparked with 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen at 100°C and 1atm. The total volume of the residual gases is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 2vol</td><td style=\"border:1px solid black;text-align:center;\">1vol</td><td style=\"border:1px solid black;text-align:center;\">2vol</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Before sparking </td><td style=\"border:1px solid black;text-align:center;\">150</td><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\">-</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">on sparking</td><td style=\"border:1px solid black;text-align:center;\">100</td><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\">100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">After sparking</td><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\">0</td><td style=\"border:1px solid black;text-align:center;\">100</td></tr></table></div> <br/> Total volume of residual gases  = (50 + 100)cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : GAY LUSSAC'S LAW OF COMBINING VOLUMES"}, {"id": "objective>Chemistry>2018-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of 2g of helium of 7g of Nitrogen exerts a total pressure of 1.5 atm. What is the partial pressure of Nitrogen in the mixture? <br/> (He = 4, N = 14)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.20atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.75atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50atm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He = 4gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=28gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  2g of He in mol = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> = 0.5mol <br/>  7g of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> in mol = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">7</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">28</span> = 0.25mol <br/>  <br/> Total mol = 0.5+0.25=0.75mol <br/>  <br/> Partial pressure of mixture = 1.5atm  <br/> Partial pressure of He = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">0.5</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.75</span>×1.5=1.0atm <br/>  <br/> Partial pressure of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">0.25</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.75</span> × 1.5=0.5atm <br/>  <br/> <strong>OR</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">helium</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td><td style=\"text-align:center;\">mol</td></tr></table></div> <br/> Number of moles of Nitrogen  = 7/14 = 0.25 mol <br/> Total number of moles of gaseous mixture = 0.5 + 0.25 <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 0.75mole <br/> Partial pressure of Nitrogen = mole fraction of nitrogen × total pressure <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\"></span> = X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">N</span> × T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">N</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25<hr size=\"1\" />0.75</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.50atm</td></tr></table></div></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2018-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrogen chloride gas reacted with oxygen gas to yield water and chlorine gas. The mole ratio of the hydrogen chloride gas to water is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4:1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balanced chemical equation for the reaction of hydrogen chloride (HCl) with oxygen (O2) to yield water (H2O) and chlorine gas (Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is 4HCl + O2 -> 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + 2Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. From this equation, we can see that the mole ratio of HCl to H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is 4:2, which simplifies to 2:1.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2018-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary component of natural gas</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">butane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural gas is a fossil fuel primarily composed of hydrocarbon gases. The primary component of natural gas is methane, which typically makes up a significant portion of the gas mixture. Methane is a simple hydrocarbon with one carbon atom and four hydrogen atoms (CH4). It is the main component of natural gas, often accounting for over 90% of its composition.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>2018-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkenes can be manufactured by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">addition of hydrogen to unsaturated vegetable oils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cracking of hydrocarbons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymerization reactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the combustion of alkanes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cracking is a chemical process in which larger hydrocarbon molecules are broken down into smaller and more useful ones. This process is commonly used in petroleum refining to convert heavy hydrocarbons into lighter fractions, including alkenes. During cracking, high-temperature and/or catalytic conditions are applied to break the long carbon chains of hydrocarbons into shorter ones. This process produces a mixture of products, including alkenes, which are unsaturated hydrocarbons containing carbon-carbon double bonds.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2018-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What are the products formed when an aqueous solution of Chlorine is exposed to sunlight?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If Chlorine water is exposed to sunlight, it gives off oxygen due to the decomposition of HClO formed between Chlorine and Water. <br/> Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> <br/> HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2018-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction with a negative enthalpy change is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adiabatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exothermic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction with a negative enthalpy change is exothermic. In an exothermic reaction, energy is released to the surroundings, hence the negative sign. The enthalpy change (ΔH) is negative because the energy of the products is less than the energy of the reactants.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2018-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the reason behind the line in the hydrogen spectroscope are due to ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loss of electrons from the atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss of neutrons from the atom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emission of energy by proton transition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emission of energy by electron transition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lines in the hydrogen spectroscope are due to the emission of energy by electron transition. When an electron in a hydrogen atom transitions from a higher energy level to a lower energy level, it emits energy in the form of light. The emitted light corresponds to a specific wavelength, which appears as a line in the spectroscope.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SIMPLE HYDROGEN SPECTRUM"}];
